mapper.select:
SELECT p.report_no AS reportNo, DATE_FORMAT(p.report_date, '%Y-%m-%d %H:%i:%s') AS reportDate, DATE_FORMAT(p.work_start_at, '%Y-%m-%d %H:%i:%s') AS workStartAt, DATE_FORMAT(p.work_end_at, '%Y-%m-%d %H:%i:%s') AS workEndAt, p.status_cd AS statusCd, p.site_cd AS siteCd, si.site_name AS siteName, p.direction_cd AS directionCd, dir.CD_CODE_NM AS directionCdNm, p.addr AS addr, au.USER_NM AS userName, p.sta_text AS staText, pp.sort_ord AS thumbSortOrd, IFNULL( CONCAT('/pothole/img/before/', p.report_no, '/', pp.sort_ord), '/assets/img/no-image.png' ) AS thumbUrl
, p.receipt_gb_cd AS receiptGbCd , c.CD_CODE_NM AS receiptGbNm FROM pothole p LEFT JOIN site_info si ON si.site_cd = p.site_cd AND si.del_yn = 'N' LEFT JOIN admin_user au ON p.receiver_id = au.USER_ID AND au.USE_YN = 1 LEFT JOIN pothole_photo pp ON pp.report_no = p.report_no AND pp.photo_gb = 'BEFORE' AND pp.is_main = 'Y' LEFT JOIN cd_common dir ON dir.CD_DIV = 'ROAD_DIR' AND dir.CD_CODE = p.direction_cd AND dir.USE_YN = 'Y' LEFT JOIN cd_common c ON p.receipt_gb_cd = c.CD_CODE and c.CD_DIV = '006' and c.USE_YN = 'Y' WHERE 1 = 1 AND p.del_yn = 'N'
AND p.report_date >= DATE_SUB(CURDATE(), INTERVAL #{recentDays} - 1 DAY) AND p.report_date < DATE_ADD(CURDATE(), INTERVAL 1 DAY)
AND p.status_cd = #{statusCd}
AND p.receipt_gb_cd = #{receiptTypeCd}
AND p.status_cd != #{excludeStatus}
AND p.report_date >= CONCAT(#{srchStrtDt}, ' 00:00:00')
AND p.report_date < DATE_ADD(CONCAT(#{srchEndDt}, ' 00:00:00'), INTERVAL 1 DAY)
AND ( au.USER_NM LIKE CONCAT('%', #{keyword}, '%') OR p.process_note LIKE CONCAT('%', #{keyword}, '%') OR p.detail_info LIKE CONCAT('%', #{keyword}, '%') OR p.addr LIKE CONCAT('%', #{keyword}, '%') )
AND ( p.site_cd IS NULL OR EXISTS ( SELECT 1 FROM road_sos.site_info child JOIN road_sos.admin_user_site aus ON aus.site_cd = COALESCE(child.parent_site_cd, child.site_cd) WHERE child.site_cd = p.site_cd AND child.del_yn = 'N' AND aus.user_id = #{userId} ) )
ORDER BY p.report_date ASC, p.report_no ASC
ORDER BY p.report_date DESC, p.report_no DESC
LIMIT #{limit}
OFFSET #{offset}

SELECT COUNT(*) FROM pothole p LEFT JOIN admin_user au ON p.receiver_id = au.USER_ID AND au.USE_YN = 1
AND p.del_yn = 'N'
AND p.report_date >= DATE_SUB(CURDATE(), INTERVAL #{recentDays} - 1 DAY) AND p.report_date < DATE_ADD(CURDATE(), INTERVAL 1 DAY)
AND p.status_cd = #{statusCd}
AND p.receipt_gb_cd = #{receiptTypeCd}
AND p.status_cd != #{excludeStatus}
AND p.report_date >= CONCAT(#{srchStrtDt}, ' 00:00:00')
AND p.report_date < DATE_ADD(CONCAT(#{srchEndDt}, ' 00:00:00'), INTERVAL 1 DAY)
AND ( au.USER_NM LIKE CONCAT('%', #{keyword}, '%') OR p.process_note LIKE CONCAT('%', #{keyword}, '%') OR p.detail_info LIKE CONCAT('%', #{keyword}, '%') OR p.addr LIKE CONCAT('%', #{keyword}, '%') )
AND ( p.site_cd IS NULL OR EXISTS ( SELECT 1 FROM site_info child JOIN admin_user_site aus ON aus.site_cd = COALESCE(child.parent_site_cd, child.site_cd) WHERE child.site_cd = p.site_cd AND child.del_yn = 'N' AND aus.user_id = #{userId} ) )

mapper.update:
UPDATE pothole
SET del_yn = 'Y',
    update_datetime = NOW(),
    update_ip = #{updateIp},
    update_id = #{userId}
WHERE report_no = #{reportNo}

